properties.style:
${function() {
    const status = describeCluster.outputs.status;
    switch (status) {
        case 'ACTIVE':
            return 'green';
        case 'FAILED':
        case 'DELETING':
            return 'red';
        case 'CREATING':
        case 'UPDATING':
        case 'PENDING':
            return 'orange';
        default:
            return 'Unknown'; // Default case for unexpected statuses
    }
}()
}

